import React, { useState, useEffect } from 'react';
import { useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import './buy.css';

function Buy() {
    //המערך שיציג את ההזמנות של הלקוח
    const [arr_orders, setArrOrders] = useState([]);
    //מצב טעינה
    const [loading, setLoading] = useState(true);
    //שליפת המשתמש הנוכחי מהסטור
    const currentUser = useSelector((state) => state.user.currentUser);

    //בעת טעינת הקומפוננטה
    useEffect(() => {
        //פונקציה לשליפת ההזמנות של הלקוח מהשרת
        const fetchOrders = async () => {
            try {
                //שליפת ההזמנות מהשרת לפי מזהה הלקוח
                const response = await fetch(`http://localhost:8080/api/shoppingApi/getShoppingByCustomerId/${currentUser.pin}`);
                //המרת התגובה לפורמט JSON
                const data = await response.json();
                //עדכון המערך המקומי עם ההזמנות שנשלפו
                setArrOrders(data);
                //במקרה שיש בעיה
            } catch (error) {
                console.error("שגיאה בשליפה", error);
            } finally {
                setLoading(false);
            }
        };
        if (currentUser && currentUser.pin) fetchOrders();
    }, [currentUser]);



    return (
        <div className="orders-container">
            <h1 className="title">היסטוריית הקניות שלי</h1>

            {loading ? (
                <p className="status-msg">טוען נתונים מהמערכת...</p>
            ) : arr_orders.length > 0 ? (
                <div className="orders-list">
                    {arr_orders.map((order) => (
                        <div key={order._id} className="order-card">
                            <div className="order-header">
                                <h3>קנייה מס' {order._id.slice(-6)}</h3>
                            </div>

                            <div className="robots-list">
                                <strong>מוצרים:</strong>
                                <ul>
                                    {order.robots && order.robots.map((robot, index) => (
                                        /* כאן המיקום המדויק של הקוד החדש */
                                        <li key={index} className="robot-item-row">
                                            <div className="robot-info-side">
                                                {robot.img && (
                                                    <img
                                                        src={"http://localhost:8080/" + robot.img}
                                                        alt={robot.robotName}
                                                        className="robot-mini-image"
                                                    />
                                                )}
                                                <span className="robot-name">{robot.robotName}</span>
                                            </div>

                                            <div className="robot-stats-side">
                                                <div className="stat-item">
                                                    <span className="stat-label">כמות</span>
                                                    <span className="stat-value">{robot.count}</span>
                                                </div>
                                                <div className="stat-item">
                                                    <span className="stat-label">מחיר</span>
                                                    <span className="stat-value">{robot.price} ₪</span>
                                                </div>
                                            </div>
                                        </li>
                                    ))}
                                </ul>
                            </div>

                            <div className="order-footer">
                                <p className="total-price"><span>{order.sum} ₪</span></p>
                            </div>
                        </div>
                    ))}
                </div>
            ) : (
                <div className="no-data">
                    <p>לא נמצאו רכישות קודמות.</p>
                </div>
            )}
        </div>
    );

}
export default Buy;
